import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjGantt } from "./OjGantt";
export { OjGantt };

/**
 * Create an instance of [[OjGantt]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojGantt(driver, By.id('my-oj-gantt'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojGantt(driver: DriverLike, by: By): Promise<OjGantt> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjGantt
  if (!(webEl instanceof OjGantt)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-gantt>`);
  }
  return webEl;
}

register("oj-gantt", OjGantt);
